module carry_save_adder (  
    input [3:0] A,  
    input [3:0] B,  
    input [3:0] C,  
    output [3:0] sum,  
    output [3:0] carry  
);  
    wire [3:0] carry_in, c2;  
    wire [3:0] s1, s2;  

    assign s1 = A ^ B;  
    assign carry_in = A & B;  

    assign s2 = s1 ^ C;  
    assign c2 = carry_in | (s1 & C);  

    assign sum = s2;  
    assign carry = c2;  
endmodule
